// ============================================================================
// RUNWAY GEN-3 - REQUEST BUILDER
// Prepare le payload pour l'API Runway Gen-3 Alpha
// URL CORRECTE: https://api.dev.runwayml.com/v1/image_to_video
// ============================================================================

const input = $input.first().json;

// Parametres d'entree
const mode = input.mode || 'text_to_video';
const promptText = input.prompt_text || input.prompt || 'Smooth camera movement, cinematic lighting';
const imageBase64 = input.image_base64 || null;
const imageUrl = input.image_url || null;
const duration = Math.min(input.duration || 5, 10); // 5 ou 10 seconds
const ratio = input.ratio || '16:9'; // 16:9, 9:16, ou 1:1

// Construire le body selon le mode
let requestBody = {};
let endpoint = '';

if (mode === 'image_to_video' && (imageBase64 || imageUrl)) {
  // Mode Image-to-Video
  endpoint = 'image_to_video';

  // Determiner le format de l'image
  let promptImage = '';
  if (imageUrl) {
    promptImage = imageUrl;
  } else if (imageBase64) {
    promptImage = imageBase64.startsWith('data:') ? imageBase64 : `data:image/png;base64,${imageBase64}`;
  }

  requestBody = {
    model: 'gen3a_turbo',
    promptImage: promptImage,
    promptText: promptText,
    duration: duration,
    ratio: ratio,
    watermark: false
  };
} else {
  // Mode Text-to-Video (Gen-3a Turbo supporte text_to_video aussi)
  endpoint = 'image_to_video';

  // Pour text-to-video, on utilise le meme endpoint mais sans promptImage
  // Note: Gen-3a_turbo peut accepter text seul dans certains cas
  requestBody = {
    model: 'gen3a_turbo',
    promptText: promptText,
    duration: duration,
    ratio: ratio,
    watermark: false
  };
}

return [{
  json: {
    request_body: requestBody,
    endpoint: endpoint,
    mode: mode,
    original_prompt: promptText,
    has_image: !!(imageBase64 || imageUrl),
    duration: duration,
    ratio: ratio
  }
}];

// ============================================================================
// RUNWAY GEN-3 - TASK ID EXTRACTOR
// Extrait le task_id de la reponse et prepare le polling
// ============================================================================

const response = $input.first().json;
const buildData = $('Build Request').item.json;

// Extraire le task_id (Runway retourne 'id' directement)
let taskId = response.id || null;
let status = response.status || 'PENDING';

if (!taskId) {
  // Essayer d'autres formats possibles
  taskId = response.task_id || response.taskId || response.data?.id;
}

if (!taskId) {
  throw new Error('No task_id received from Runway API. Response: ' + JSON.stringify(response));
}

return [{
  json: {
    task_id: taskId,
    initial_status: status,
    mode: buildData.mode,
    original_prompt: buildData.original_prompt,
    duration: buildData.duration,
    ratio: buildData.ratio,
    poll_count: 0,
    max_polls: 60 // 60 polls x 5s = 5 minutes max
  }
}];

// ============================================================================
// RUNWAY GEN-3 - STATUS CHECKER
// Verifie le statut et decide si on continue le polling
// Statuts possibles: PENDING, RUNNING, SUCCEEDED, FAILED, CANCELLED
// ============================================================================

const pollResponse = $input.first().json;
const previousData = $('Wait 5s').item.json;

// Extraire le statut
let status = pollResponse.status || 'PENDING';
let videoUrl = null;
let error = null;
let progress = pollResponse.progress || 0;

// Extraire l'URL de la video si terminee
if (pollResponse.output && Array.isArray(pollResponse.output) && pollResponse.output.length > 0) {
  videoUrl = pollResponse.output[0];
} else if (pollResponse.outputUrl) {
  videoUrl = pollResponse.outputUrl;
} else if (pollResponse.artifacts && pollResponse.artifacts[0]) {
  videoUrl = pollResponse.artifacts[0].url;
}

// Extraire l'erreur si echec
if (pollResponse.failure || pollResponse.error) {
  error = pollResponse.failure || pollResponse.error;
}

const pollCount = (previousData.poll_count || 0) + 1;
const maxPolls = previousData.max_polls || 60;

// Determiner si on doit continuer
const isComplete = status === 'SUCCEEDED' || status === 'COMPLETED';
const isFailed = status === 'FAILED' || status === 'CANCELLED' || pollCount >= maxPolls;
const shouldContinue = !isComplete && !isFailed;

return [{
  json: {
    task_id: previousData.task_id,
    status: status,
    progress: progress,
    video_url: videoUrl,
    error: error,
    is_complete: isComplete,
    is_failed: isFailed,
    should_continue: shouldContinue,
    poll_count: pollCount,
    max_polls: maxPolls,
    mode: previousData.mode,
    original_prompt: previousData.original_prompt,
    duration: previousData.duration,
    ratio: previousData.ratio
  }
}];

// ============================================================================
// RUNWAY GEN-3 - SUCCESS OUTPUT
// Structure la reponse finale pour l'Agent Principal
// ============================================================================

const data = $input.first().json;

return [{
  json: {
    success: true,
    tool: 'runway_gen3',
    video: {
      url: data.video_url,
      task_id: data.task_id,
      duration: data.duration,
      ratio: data.ratio,
      mode: data.mode,
      prompt_used: data.original_prompt,
      status: 'SUCCEEDED',
      model: 'gen3a_turbo',
      polls_taken: data.poll_count
    },
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// RUNWAY GEN-3 - FAILURE OUTPUT
// Retourne une erreur structuree
// ============================================================================

const data = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'runway_gen3',
    error: {
      message: data.error || 'Video generation failed or timed out',
      status: data.status,
      task_id: data.task_id,
      polls_taken: data.poll_count
    },
    video: null,
    generated_at: new Date().toISOString()
  }
}];
